          // Arrays to store last seen positions of characters
          let m1 = Array(256).fill(0), m2 = Array(256).fill(0);

          // Get the length of the strings
          let n = s.length;

          // Iterate through each character of both strings
          for (let i = 0; i < n; ++i) {
