              if (m1[s.charCodeAt(i)] !== m2[t.charCodeAt(i)]) return false;

              // Update positions with current index + 1
              m1[s.charCodeAt(i)] = i + 1;
              m2[t.charCodeAt(i)] = i + 1;
          }

          // Return true if all mappings are valid
          return true;
      }
  }

